When I have a function returning a pointer, for some types (std::string*, int*) returning a nullptr segfaults, for others (char*, Class*) it returns None.

If it's a known limitation then take this issue as a feature request to handle nullptr in all cases.

Example:
rtest.cc
```cpp
#include <string>
#include <pybind11/pybind11.h>

namespace py = pybind11;

struct Custom { std::string s; };

int* r_int(bool nil) { static int v=12; return nil ? nullptr : &v; }
Custom* r_cust(bool nil) { static Custom v={"a"}; return nil ? nullptr : &v; }
std::string* r_str(bool nil) { static std::string v="b"; return nil ? nullptr : &v; }
char* r_char(bool nil) { static char v[]="c"; return nil ? nullptr : v; }

PYBIND11_PLUGIN(rtest) {
    py::module m("rtest", "");
    py::class_<Custom>(m, "Custom").def(py::init<>()).def_readwrite("s", &Custom::s);
    m.def("r_int", &r_int, py::return_value_policy::reference);
    m.def("r_cust", &r_cust, py::return_value_policy::reference);
    m.def("r_str", &r_str, py::return_value_policy::reference);
    m.def("r_char", &r_char, py::return_value_policy::reference);
    return m.ptr();
}
```
rtest.py
```py
from rtest import *

print r_int(False)
print r_cust(False)
print r_str(False)
print r_char(False)

print r_int(True)  # segfault
print r_cust(True)
print r_str(True)  # segfault
print r_char(True)
```

I'm trying to assign a Python function to a C++ class member of type `std::function`. Here is the code:

```C++
class Test
{
public:
    int Foo(int param)
    {
        if (callback)
            callback(param);
    }

    std::function<void(int)> callback;
};

// pybind11 binding:
namespace py = pybind11;
using namespace pybind11::literals;

PYBIND11_PLUGIN(PyProject1) {
    py::module m("PyProject1", "PyProject1 example plugin");

    py::class_<Test>(m, "Test")
        .def(py::init<>())
        .def("Foo", &Test::Foo, "param"_a)
        .def_readwrite("callback", &Test::callback)
    ;

    return m.ptr();
}
```

Python test code:
```python
import PyProject1 as pp

t = pp.Test()

def py_callback(a):
    print('param: {0}'.format(a))

t.callback = py_callback   # <--- exception here!
t.Foo(param=42)
```
The code compiles fine. At run time when I'm trying to assign a Python function to the `Test::callback` member I'm getting this exception:
```
Incompatible function arguments. The following argument types are supported:

    1. (PyProject1.Test, std::function<void __cdecl(int)>) -> NoneType

    Invoked with: <PyProject1.Test object at 0x00000150A3EA4CE0>, <function py_callback at 0x00000150A3E48950>
```

How can I assign a Python callback function to a C++ class member of type `std::function`?

